INSERT INTO `events` VALUES (4,'Grand Opening','open-beta','GRAND OPENING','purple','Chú Bé Rồng Online chính thức mở cửa! Tham gia ngay để nhận quà khai trương siêu khủng!','2026-04-25','2026-05-25','<h3>🎊 Grand Opening - Chú Bé Rồng Online</h3><p>Server chính thức đã mở! Mọi dữ liệu sẽ được giữ nguyên. Tham gia ngay để nhận quà khai trương!</p><ul><li>🎁 <strong>GiftCode OPEN2026</strong>: Mở thành viên FREE + 10.000 Thỏi Vàng + 200.000 Hồng Ngọc + 50 triệu Vàng + 1.000 Đá Ngũ Sắc + Radar</li><li>📺 <strong>GiftCode MTDLIVE</strong>: Phát trên live stream hàng ngày!</li><li>⚡ Tốc độ EXP: x36</li><li>📊 TNSM: x0.3 (cân bằng chính thức)</li><li>🎮 3 Chủng tộc: Trái Đất, Namếc, Xayda</li></ul>','[{\"icon\":\"⚡\",\"title\":\"Tốc Độ EXP\",\"desc\":\"Luyện tập siêu nhanh\",\"value\":\"x36\"},{\"icon\":\"🎁\",\"title\":\"GiftCode Khai Trương\",\"desc\":\"Nhận quà miễn phí khi tham gia\",\"value\":\"FREE\"},{\"icon\":\"🚀\",\"title\":\"Grand Opening\",\"desc\":\"Server chính thức - không reset\",\"value\":\"OPEN\"}]','OPEN2026','Code khai trương: Mở thành viên + 10K Thỏi Vàng + 200K Hồng Ngọc + 50TR Vàng + 1000 Đá Ngũ Sắc + Radar',1,1,1,'2026-04-10 12:36:37','2026-04-25 16:14:52'),(5,'Sự Kiện Hè 2026','su-kien-he','SỰ KIỆN HÈ','orange','Mùa hè bùng nổ cùng Chú Bé Rồng Online! Săn boss nhận quà siêu hot!','2026-06-01','2026-08-31','<p>Sự kiện mùa hè với hàng loạt mini-game, boss event và phần thưởng cực khủng!</p><ul><li>Boss Hè xuất hiện mỗi 2 giờ</li><li>Drop rate x5 trong suốt sự kiện</li><li>Nhiệm vụ hè với phần thưởng độc quyền</li></ul>','[{\"icon\":\"☀️\",\"title\":\"Boss Hè\",\"desc\":\"Boss đặc biệt mùa hè\",\"value\":\"x2h\"},{\"icon\":\"💎\",\"title\":\"Drop Rate\",\"desc\":\"Tỷ lệ rơi đồ tăng gấp 5\",\"value\":\"x5\"},{\"icon\":\"🏆\",\"title\":\"Giải Thưởng\",\"desc\":\"Top BXH nhận quà VIP\",\"value\":\"TOP 50\"}]','','',0,0,2,'2026-04-10 12:36:37','2026-04-10 12:36:37'),(6,'Giỗ Tổ Hùng Vương 2026','hung-vuong','GIỖ TỔ HÙNG VƯƠNG','red','Kỷ niệm ngày Giỗ Tổ Hùng Vương - Tri ân nguồn cội!','2026-04-06','2026-04-10','<p>Nhân dịp lễ Giỗ Tổ Hùng Vương 10/03 Âm lịch, Chú Bé Rồng Online tổ chức sự kiện đặc biệt!</p><ul><li>EXP x10 trong suốt kỳ nghỉ lễ</li><li>Boss Lạc Long Quân xuất hiện đặc biệt</li><li>GiftCode lễ hội cho tất cả người chơi</li></ul>','[{\"icon\":\"🏛️\",\"title\":\"EXP Lễ Hội\",\"desc\":\"Tăng tốc luyện tập dịp lễ\",\"value\":\"x10\"},{\"icon\":\"🐉\",\"title\":\"Boss Lễ\",\"desc\":\"Boss đặc biệt Lạc Long Quân\",\"value\":\"Hiếm\"},{\"icon\":\"🎊\",\"title\":\"Quà Lễ\",\"desc\":\"Phần thưởng cho tất cả\",\"value\":\"FREE\"}]','HUNGVUONG2026','Nhập code để nhận quà lễ Giỗ Tổ',0,0,3,'2026-04-10 12:36:37','2026-04-10 12:36:37');
