INSERT INTO `notify` VALUES (0,'Sự Kiện NOEL','ĐIỀU ƯỚC ĐÊM ĐÔNG\r\n\r\nChào các cư dân,\r\n\r\nNhân dịp mùa Giáng Sinh đã về, Admin xin thông báo chuỗi Sự kiện Giáng Sinh 2024 sẽ được cập nhật sau bảo trì tối nay.\r\n\r\nNội dung sự kiện bao gồm:\r\n\r\nKhuyến mãi x3 nạp thẻ\r\n\r\nĐổi điểm tại NPC Quy Lão\r\n\r\nĐiều Ước Đêm Đông\r\n\r\nSăn Boss Cooler Vàng\r\n\r\nTrang trí Cây Thông Noel\r\n\r\nTìm Tuần Lộc Thất Lạc\r\n\r\nQuà tặng từ Ông Già Noel\r\n\r\nShop Noel tại NPC Chi Chi\r\n\r\nVòng Quay Thượng Đế\r\n\r\nĐiều chỉnh mới\r\n\r\nThời gian kết thúc sự kiện: ngày 17/01/2025\r\n\r\n1. KHUYẾN MÃI X3 NẠP THẺ\r\n\r\nKhuyến mãi x3 tất cả giá trị thẻ nạp.\r\nThời gian: từ 00h10 ngày 24/12/2024 đến 23h59 ngày 26/12/2024.\r\n\r\n2. ĐỔI ĐIỂM TẠI NPC QUY LÃO\r\n\r\nThời gian áp dụng đến hết ngày 30/12/2024.\r\n\r\nMỗi 1 ngọc nạp nhận được 1 điểm.\r\n\r\nĐến NPC Quy Lão để đổi điểm.\r\n\r\nDanh sách vật phẩm đổi:\r\n\r\nHộp Cadic VIP\r\n\r\nHộp Gokuday VIP\r\n\r\nVán bay Cây Thông\r\n\r\nPhong Hỏa Luân\r\n\r\nDụng cụ học tập (cờ đeo lưng)\r\n\r\nHỏa Tiêm Thương\r\n\r\nBlack Goku Rose\r\n\r\nPet Capybara đeo balo\r\n\r\nPet Capybara\r\n\r\nPet Chim Cánh Cụt\r\n\r\n3. ĐIỀU ƯỚC ĐÊM ĐÔNG\r\n\r\nNgười chơi thu thập Ngọc Rồng Băng để triệu hồi Rồng Thần Băng.\r\n\r\nRồng Thần Băng có tổng cộng 5 điều ước.\r\n\r\nMỗi ngày tối đa 15 lần gọi Rồng Thần Băng.\r\n\r\nCách nhận Ngọc Rồng Băng:\r\n\r\nĐánh quái thường: nhận Ngọc Rồng Băng 7 sao (tối đa 99 viên/ngày).\r\n\r\nMap sự kiện, Cold, Hành tinh Thực vật: Ngọc Rồng Băng 6 sao (tối đa 10 viên/ngày).\r\n\r\nHoàn thành nhiệm vụ Bò Mộng: Ngọc Rồng Băng 5 sao (tối đa 10 viên/ngày).\r\n\r\nPhó bản, siêu quái, boss: Ngọc Rồng Băng 4 sao (tối đa 12 viên/ngày).\r\n\r\nGiải Nhi Đồng, Siêu Cấp 1–3: Ngọc Rồng Băng 3 sao (tối đa 10 viên/ngày).\r\n\r\nSăn ăn trộm, ở dơ, sói: Ngọc Rồng Băng 2 sao (tối đa 10 viên/ngày).\r\n\r\nSăn boss Cumber, Xên: Ngọc Rồng Băng 1 sao (tối đa 5 viên/ngày).\r\n\r\nLưu ý:\r\n\r\nSức mạnh dưới 10 tỷ không thể đổi nội tại.\r\n\r\nNgọc Rồng Băng chỉ được ký gửi bằng ngọc.\r\n\r\nCần chừa ô hành trang trống để nhận vật phẩm.\r\n\r\nSau khi kết thúc sự kiện, vật phẩm sự kiện trên shop sẽ bị thu hồi và tự động xóa sau 7 ngày.\r\n\r\n4. SĂN BOSS COOLER VÀNG\r\n\r\nNgười chơi đến NPC Cây Thông để vào map săn boss.\r\n\r\nPhần thưởng gồm:\r\n\r\nĐồ Thần Linh\r\n\r\nVán bay vĩnh viễn\r\n\r\nNgọc và nhiều vật phẩm giá trị khác\r\n\r\n5. TRANG TRÍ CÂY THÔNG NOEL\r\n\r\nCùng nhau thu thập vật liệu để trang trí Cây Thông Noel và nhận thưởng.\r\n\r\nCách tìm vật liệu:\r\n\r\nChuông đồng: đánh quái map lạnh (được giao dịch).\r\n\r\nQuả châu: đánh quái Hành tinh Thực vật (được giao dịch).\r\n\r\nNgôi sao: đánh quái trong phó bản (được giao dịch).\r\n\r\nDây kim tuyến: nhiệm vụ khó tại Bò Mộng (được giao dịch).\r\n\r\nMóc treo Noel: bán tại NPC Chi Chi (10 triệu vàng).\r\n\r\nPhần thưởng:\r\n\r\nCơ hội nhận vật phẩm vĩnh viễn, đặc biệt là cờ đeo lưng chống lạnh.\r\n\r\nNhận buff x2 – x3 Tiềm năng và Sức mạnh khi trang trí cây.\r\n\r\n6. TÌM TUẦN LỘC THẤT LẠC\r\n\r\nTrong quá trình tham gia sự kiện, người chơi có thể gặp Tuần Lộc đi lạc.\r\n\r\nChat “ec ec” để Tuần Lộc đi theo.\r\n\r\nDẫn Tuần Lộc về cho Ông Già Noel để nhận thưởng ngẫu nhiên.\r\n\r\nPhần thưởng gồm vật phẩm và Ngọc Rồng Băng từ 1 đến 7 sao.\r\n\r\nCó cơ hội nhận Pet Tuần Lộc vĩnh viễn.\r\n\r\n7. QUÀ TẶNG TỪ ÔNG GIÀ NOEL\r\n\r\nNgười chơi sử dụng Vớ Noel để tặng NPC Quy Lão Noel và nhận quà ngẫu nhiên.\r\n\r\nVớ Noel bán tại NPC Chi Chi.\r\n\r\nCó thể nhận khi đánh siêu quái hoặc boss trong phó bản.\r\n\r\n8. SHOP NOEL TẠI NPC CHI CHI\r\n\r\nMở bán các vật phẩm sự kiện và cải trang Noel trong thời gian diễn ra sự kiện.\r\n\r\n9. VÒNG QUAY THƯỢNG ĐẾ\r\n\r\nDanh sách phần thưởng:\r\n\r\nCT Frieren\r\n\r\nBó hoa hồng\r\n\r\nBó hoa vàng\r\n\r\nBulma Ả Rập\r\n\r\n10. ĐIỀU CHỈNH MỚI\r\n\r\nĐồ sao pha lê sẽ không còn rơi tại 3 map gần làng để hỗ trợ người chơi làm nhiệm vụ dễ dàng hơn.\r\n\r\nChúc toàn thể cư dân có một mùa Giáng Sinh an lành và vui vẻ.'),(1,'Hỗ trợ nhiệm vụ','1) Hỗ trợ nhiệm vụ TĐST:\r\nNgày thứ 2-3-4 trong tuần từ 5h\r\nđến 7h và từ 17h đến hết 19h,\r\nchỉ những cư dân đang làm nhiệm\r\nvụ này mới vào được map có boss,\r\nnày xuất hiện.\r\n(Núi khỉ đen, hang khỉ đen, núi khỉ\r\nđỏ).\r\n\r\n2) Hỗ trợ nhiệm vụ Xên Bọ Hung:\r\nNgày thứ 2-3-4 trong tuần, từ 2 giờ\r\nsáng đén hết 4 giờ sáng và từ 2 giờ\r\nchiều đến hết 4 giờ chiều, chỉ\r\nnhững cư dân đang làm nhiệm vụ\r\nnày mới vào được map có boss này\r\nxuất hiện.\r\n(Thị trấn Ginder, Võ đài Xên bọ\r\nhung).'),(2,'Mốc sức mạnh','Phần thưởng khi đạt ngưỡng Sức Mạnh:\r\n\r\n1)100 triệu Sức Mạnh:\r\nNhận phần thưởng cơ bản hỗ trợ tân thủ.\r\n2)1 tỷ Sức Mạnh:\r\nNhận vật phẩm tăng tốc luyện tập.\r\n3)20 tỷ Sức Mạnh:\r\nNhận quà trung cấp, bao gồm vật phẩm hỗ trợ chiến đấu.\r\n4)50 tỷ Sức Mạnh:\r\nNhận rương trang bị hiếm (ngẫu nhiên).\r\n5)70 tỷ Sức Mạnh:\r\nNhận set thời trang đặc biệt sự kiện.\r\n6)100 tỷ Sức Mạnh:\r\nNhận danh hiệu VIP và quà cấp cao.\r\n7)180 tỷ Sức Mạnh:\r\nNhận vật phẩm cực hiếm và vào bảng vàng vinh danh.');
/*!40000 ALTER TABLE `notify` ENABLE KEYS */;
UNLOCK TABLES;

