INSERT INTO `posts` VALUES (1,'🚀 Grand Opening MTDGame - Chính Thức Open, GiftCode & Cơ Chế Server','<h2>🚀 MTDGame chính thức Grand Opening</h2>\n<p>Xin chào các chiến binh, vũ trụ MTDGame đã bước vào giai đoạn <strong>Open chính thức</strong>. Dữ liệu người chơi được vận hành ổn định, định hướng lâu dài và không reset theo mốc Grand Opening.</p>\n<h3>🎁 GiftCode khai trương</h3>\n<ul>\n<li><strong>OPEN2026</strong>: Mở thành viên FREE, 10.000 Thỏi Vàng, 200.000 Hồng Ngọc, 50 triệu Vàng, 1.000 Đá Ngũ Sắc và Radar.</li>\n<li><strong>MTDLIVE</strong>: Code live hằng ngày, dùng để mở thành viên và nhận quà hỗ trợ tân thủ.</li>\n<li>Các code test/beta quá mạnh đã được tắt để giữ cân bằng kinh tế server.</li>\n</ul>\n<h3>⚡ Tốc độ sức mạnh & tiềm năng</h3>\n<ul>\n<li>EXP server hiện tại: <strong>x36</strong>.</li>\n<li>Cơ chế TNSM chính thức đã cân bằng về <strong>x0.3</strong> ở game server.</li>\n<li>Sau các mốc sức mạnh cao, hệ thống tự giảm TNSM để tránh dame ảo và giữ nhịp cày bền.</li>\n</ul>\n<h3>⚔️ Game thuộc dạng nào?</h3>\n<p>Server đi theo hướng <strong>tầm trung - cân bằng</strong>, không phải dạng dame ảo full chỉ số ngay từ đầu. Người chơi vẫn có tốc độ phát triển nhanh nhờ EXP x36 và quà mở server, nhưng tài nguyên lớn, đồ mạnh và set hiếm sẽ được kiểm soát để giữ giá trị lâu dài.</p>\n<h3>👥 Chủng tộc & đệ tử</h3>\n<ul>\n<li>Game có đủ 3 hệ chính: <strong>Trái Đất, Namếc, Xayda</strong>.</li>\n<li>Đệ tử có nhiều trạng thái: đi theo, bảo vệ, tấn công, về nhà, hợp thể.</li>\n<li>Source đang có nhiều nhóm đệ/skin đệ khác nhau, hỗ trợ các dạng hợp thể nâng cao như Porata và Gogeta tùy vật phẩm.</li>\n</ul>\n<h3>🧭 Luồng nhiệm vụ</h3>\n<ul>\n<li>Nhiệm vụ chính chạy theo tuyến NPC - map - quái - boss.</li>\n<li>Các mốc đầu game hướng dẫn lấy Radar, thu hoạch đậu, đánh mộc nhân, nhặt đùi gà, cứu em bé.</li>\n<li>Về sau mở tuyến bang hội, tiêu diệt boss, map tương lai, Android, Cell, Mabu và các mốc sức mạnh.</li>\n</ul>\n<h3>💎 Săn SKH, đồ hiếm và đãi ngộ</h3>\n<ul>\n<li>SKH/đồ hiếm sẽ được định hướng qua hoạt động boss, sự kiện, map cao cấp và các đợt live.</li>\n<li>Tỉ lệ rơi sẽ được giữ ở mức có giá trị, không xả tràn làm mất cân bằng.</li>\n<li>Người chơi mới có GiftCode mở thành viên và tài nguyên nền để bắt nhịp nhanh.</li>\n<li>Người chơi chăm hoạt động, đi boss, tham gia bang hội và theo dõi live sẽ có lợi thế ổn định.</li>\n</ul>\n<h3>📌 Kết luận</h3>\n<p>MTDGame sẽ vận hành theo hướng <strong>vũ trụ thu nhỏ cân bằng</strong>: admin có quyền can thiệp khi cần, nhưng kinh tế và sức mạnh người chơi sẽ được giữ để server sống lâu. Chúc các chiến binh săn ngọc rồng vui vẻ!</p>','admin','2026-04-25 15:53:35',0,1,NULL,0,0,0,112),(2,'📢 [PATCH NOTES] Tổng Hợp Cập Nhật Server MTDGame - Tháng 4/2026','🔥 TỔNG HỢP CẬP NHẬT SERVER MTDGame 🔥\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nChào các chiến binh! Admin tổng hợp toàn bộ update gần đây để anh em nắm rõ tình hình server. Đọc kỹ nhé!\n\n═══════════════════════════════\n🎉 1. SỰ KIỆN GIỖ TỔ HÙNG VƯƠNG\n═══════════════════════════════\n✅ Đã triển khai sự kiện Giỗ Tổ Hùng Vương hoàn chỉnh!\n• NPC Hùng Vương xuất hiện tại Đảo Kame\n• Boss Sơn Tinh & Thuỷ Tinh spawn liên tục trên 3 hành tinh\n• Boss Voi Chín Ngà, Gà Chín Cựa, Ngựa Chín Hồng Mao drop lễ vật\n• Quy đổi vật phẩm: 50 Ngà + 50 Cựa + 50 Hồng Mao → Hộp Quà Cao Cấp + 20 điểm\n• Đổi 99 Dưa Hấu → +10 điểm BXH\n• Cải trang VIP: Sơn Tinh / Thuỷ Tinh / Mị Nương (50 lễ vật mỗi loại, hạn 30 ngày)\n• Linh Thú Huyền Thoại: Pet Voi / Gà / Ngựa (99 lễ vật + 20 Thỏi Vàng)\n• Chúc Phúc: +50 điểm sự kiện (5 Thỏi Vàng)\n• BXH Dưa Hấu & BXH Sơn Tinh - Thuỷ Tinh\n\n═══════════════════════════════\n💰 2. CÂN BẰNG KINH TẾ GAME\n═══════════════════════════════\n✅ Giá bùa đã sửa lại y như bản Teamobi (giảm giá)\n✅ Thỏi vàng tân thủ tăng từ 30TV → 500TV (cho ae dễ thở hơn)\n✅ Giá mảnh hồn bông tai trong shop: giảm từ 2 tỷ → 10M vàng/mảnh\n✅ Mở chỉ số bông tai khê: 2k thỏi 1 hit\n✅ Boss TDST (Namec) & Boss Bojack (Trái Đất): thêm drop Hồng Ngọc + Thỏi Vàng\n✅ Quà tân thủ buff mạnh: Vàng x4, Ngọc Xanh x2.5, Sức Mạnh x3, Tiềm Năng x3\n✅ Kéo Búa Bao: mức cược mới 100k/500k/1M (hợp lý hơn)\n✅ Xóa bỏ Tài Xỉu khỏi NPC Lý Tiểu Nương\n\n═══════════════════════════════\n🛒 3. HỆ THỐNG GÓI VIP & ĐỆ TỬ\n═══════════════════════════════\n✅ 3 Gói VIP Tuần tại NPC Lý Tiểu Nương:\n  • VIP 1 (40K VNĐ): 100 TV + 3 Bình TNSM + 10 Đá Bảo Vệ + 3 Phiếu GG\n  • VIP 2 (80K VNĐ - Gốc 100K sale 20%): 500 TV + Danh Hiệu VIP 7 ngày\n  • VIP 3 (400K VNĐ - Gốc 500K sale 20%): 2000 TV + 5 Ngọc Rồng 1 Sao + Danh Hiệu VIP\n  • Giới hạn 1 lần/7 ngày\n\n✅ 4 Gói Đệ Tử Ngày:\n  • Gói 1 (16K): Đệ Tử Thường + 50 TV\n  • Gói 2 (40K): Đệ Tử Thường + 200 TV + 10 ĐBV\n  • Gói 3 (80K): Đệ Tử Mabu + 500 TV + 20 ĐBV\n  • Gói 4 (160K): Đệ Tử Black Goku + 1000 TV + 30 ĐBV\n  • Giới hạn 1 lần/ngày\n\n✅ Flash Sale: Admin gõ \"flashsale\" trong chat → giảm thêm 30%!\n\n═══════════════════════════════\n🔧 4. SỬA LỖI & BẢO MẬT\n═══════════════════════════════\n✅ Fix lỗi Kéo Búa Bao bên Lý Tiểu Nương (auto chọn búa → hoà/thắng)\n✅ Fix Ngọc Rồng Sao Đen bị lỗi tự nhận đồ sau 30 phút\n✅ Fix Rồng 1 Sao lỗi ước không nâng được găng\n✅ Fix lỗi encoding hiển thị (tiếng Việt lỗi font)\n✅ Fix luồng ATM auto (nạp tiền tự động)\n✅ Fix mở rộng túi vàng bị exploit (item 988)\n✅ Vá lỗ hổng buff VND\n✅ Fix NullPointerException khi client disconnect sớm\n✅ Fix sửa quà ước NRO 1, chỉnh trang thêm chỉ số\n\n═══════════════════════════════\n🏹 5. TÍNH NĂNG MỚI\n═══════════════════════════════\n✅ Sự kiện Loan Tin: đăng bài trên diễn đàn + duyệt bởi admin → nhận quà\n✅ Hệ hành tinh Majin (Manji) mới\n✅ Cải trang mới: Vòng Quay Thượng Đế (chi tiết quà để user theo dõi)\n✅ Log truy vấn giao dịch giữa các người chơi (chống gian lận)\n✅ Cửa hàng Satan: chỉnh sửa giá ngọc xanh mua skill Urun\n✅ NPC Mr. PoPo: fix tương tác đúng trên mọi map\n✅ NPC Gohan Ultra: spawn tại 3 map starter (map 1, 8, 15) hướng dẫn SKH\n✅ Hệ thống phát hiện gian lận tự động (multi-tier)\n\n═══════════════════════════════\n🛡️ 6. ADMIN TOOLS & BẢO TRÌ\n═══════════════════════════════\n✅ Panel quản trị nâng cấp: phân quyền, buff item, quản lý account\n✅ Hệ thống audit log: theo dõi giao dịch VND/Cash/ATM\n✅ Mass-action: ban/unban nhiều tài khoản cùng lúc\n✅ Fraud detection script tự động (PowerShell + SQL)\n\n═══════════════════════════════\n📌 LƯU Ý CHO AE\n═══════════════════════════════\n• Phát hiện bug → báo ngay trên Diễn Đàn hoặc Zalo admin\n• Lợi dụng bug/exploit → BAN vĩnh viễn, không cảnh cáo\n• Server mở 24/7, restart khi cần thiết để apply update\n• Nạp ATM tự động: chuyển khoản đúng cú pháp để nhận coin tức thì\n\nChúc các chiến binh chơi game vui vẻ! 🎮\nMọi góp ý vui lòng gửi tại mục Góp Ý trên website.\n\n— Admin MTDGame —','admin','2026-04-29 10:49:50',0,1,NULL,0,0,0,13),(3,'🏆 [TUYÊN DƯƠNG] Quỹ Ủng Hộ & Bảng Vàng Đóng Góp Server','🏆 BẢNG TUYÊN DƯƠNG — QUỸ ỦNG HỘ SERVER 🏆\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\nServer MTDGame được duy trì & phát triển hoàn toàn bởi tâm huyết của admin — từng dòng code, từng tính năng, từng bản fix bug đều được chăm chút kỹ lưỡng mỗi ngày.\n\nKhi bạn ủng hộ quỹ phát triển, bạn không chỉ nhận được vật phẩm in-game mà quan trọng hơn — bạn đang giúp admin có thêm động lực để tiếp tục xây dựng một server ổn định, công bằng và ngày càng hay hơn cho cộng đồng.\n\n═══════════════════════════════\n💛 Ý NGHĨA CỦA MỖI ĐỒNG ỦNG HỘ\n═══════════════════════════════\n\n🖥️ Duy trì máy chủ 24/7 — hosting, bandwidth, bảo mật\n🔧 Phát triển tính năng mới — sự kiện, NPC, boss, quest\n🛡️ Bảo trì hệ thống — fix bug, chống hack, cân bằng game\n📱 Nâng cấp trải nghiệm — website, diễn đàn, hệ thống nạp\n🤝 Xây dựng cộng đồng — hỗ trợ người chơi, sự kiện offline\n\n═══════════════════════════════\n⭐ BẢNG VÀNG TUYÊN DƯƠNG\n═══════════════════════════════\n\nTất cả những ai ủng hộ quỹ phát triển đều được ghi nhận mãi mãi tại đây.\nMỗi đồng ủng hộ là một viên gạch xây dựng thế giới Ngọc Rồng!\n\n🛡️ Admin — Founder & Lead Developer\n• Thiết kế kiến trúc server từ A-Z\n• Deploy & vận hành 24/7 bằng tâm huyết\n• Phát triển 15+ tính năng mới trong tháng 4\n• Fix 20+ bug critical cho server ổn định\n\n═══════════════════════════════\n📢 CÁCH THAM GIA ĐÓNG GÓP\n═══════════════════════════════\n\n🔹 Ủng hộ quỹ phát triển → Trang \"Ủng Hộ & Nạp Quỹ\" trên website\n   (Bạn sẽ nhận được vật phẩm in-game tương ứng)\n\n🔹 Báo cáo bug → Đăng bài chi tiết tại Diễn Đàn\n🔹 Đề xuất tính năng → Gửi tại mục Góp Ý\n🔹 Giúp đỡ tân thủ → Hướng dẫn trên Diễn Đàn\n\nMọi đóng góp — dù lớn hay nhỏ — đều được ghi nhận!\nTên bạn sẽ xuất hiện trên Bảng Vàng server mãi mãi! 🌟\n\n═══════════════════════════════\n\n\"Một server hay không phải do admin làm một mình,\nmà là cả cộng đồng cùng xây dựng.\"\n\nCảm ơn tất cả chiến binh đã và đang đồng hành! 💛\n\n— Admin MTDGame —','admin','2026-04-29 10:49:50',0,1,NULL,0,0,0,6);
